var Roblox=Roblox||{};Roblox.Lang=Roblox.Lang||{};Roblox.Lang['Authentication.OneTimePasscode']={"Action.Agree":"Zustimmen","Action.ChangeEmail":"E-Mail-Adresse ändern","Action.ChangeEmailAddress":"E-Mail-Adresse ändern","Action.ChangeEmailV2":"E-Mail ändern","Action.Continue":"Weiter","Action.DidntReceiveCode":"Code nicht erhalten? Klicke hier","Action.GetHelp":"Hilfe holen","Action.LearnMoreOneTimeCode":"Mehr über einmaligen Code erfahren","Action.OptionalPersonalInformation":"optionalen personenbezogenen Daten","Action.OverseasPersonalInformationTransfer":"Übermittlung von personenbezogenen Daten ins Ausland","Action.PrivacyPolicy":"Datenschutzrichtlinie","Action.RequiredPersonalInformation":"erforderlichen personenbezogenen Daten","Action.Resend":"Erneut senden","Action.ResendCode":"Code erneut senden","Action.TermsAndConditions":"Nutzungsbedingungen","Action.ThirdPartyPersonalInformationProvision":"Bereitstellung personenbezogener Daten durch Dritte","Action.TryAnotherWay":"Eine andere Methode versuchen","Description.ConsentToAllTerms":"Allen Bedingungen zustimmen, einschließlich erforderlicher und optionaler Bedingungen.","Description.CSChatbotOneTimePasscodeEmail.V1.Subject":"Einmaliger Roblox-Kundensupport-Code","Description.CSChatbotOneTimePasscodeEmailV1.Body":"Hallo,{lineBreak}{lineBreak}danke, dass du den Roblox-Kundensupport-Chatbot betreffs des Problems mit deinem Konto {username} kontaktiert hast.{lineBreak}Ein Code wird benötigt, um mit der eingereichten Chatbot-Anfrage fortzufahren. Bitte gib den folgenden Code im Roblox-Kundensupport-Chatbot ein: {boldStart}{code}{boldEnd}.{lineBreak}{lineBreak}Verwende diesen Code ausschließlich für den Roblox-Kundensupport-Chatbot.{lineBreak}Wenn du diesen Code nicht angefordert hast, kannst du diese E-Mail einfach ignorieren.{lineBreak}{lineBreak}Vielen Dank{lineBreak}{lineBreak}Das Roblox-Team","Description.DidntReceiveCode":"Code nicht erhalten?","Description.EnterCode":"Ein einmaliger Code wurde gerade an deine E-Mail-Adresse gesendet, wenn sie auf deinem Konto verifiziert ist. Gib den Code ein, den wir gerade hierhin gesendet haben:","Description.EnterCodeHelp":"Ein einmaliger Code wurde an deine E-Mail-Adresse gesendet, wenn sie auf deinem Konto verifiziert ist. Gib den Code ein, den wir hierhin gesendet haben:","Description.EnterCodeHelpV2":"Gib den Code ein, den wir gerade gesendet haben an:","Description.EnterCodeHelpV3":"Gib den Code ein, den wir gerade an {email} gesendet haben","Description.KoreaConsentTerms":"Bitte lies und akzeptiere die folgenden Bedingungen. Du hast die Wahl, den einzelnen Bedingungen zuzustimmen oder nicht zuzustimmen. Du darfst weiterhin Roblox verwenden, wenn du den optionalen Bedingungen nicht zustimmst. ","Description.LoginOneTimePasscodeEmail.V1.Body":"Hallo,{lineBreak}{lineBreak}{boldStart}{code}{boldEnd} ist dein einmaliger Roblox-Code. Gib ihn im Anmeldebildschirm ein, um dich anzumelden.{lineBreak}{lineBreak}Teile diesen Code mit {boldStart}niemandem{boldEnd}. Wir werden dich {boldStart}niemals{boldEnd} kontaktieren, um deinen Code zu erfragen. Wenn du diesen Code nicht angefordert hast, musst du nichts weiter tun. Wenn du mehrere Codes erhalten hast, die du nicht angefordert hast, raten wir dir dringend, eine andere E-Mail-Adresse mit deinem Konto zu verbinden und {linkTagWithAuthenticatorHelpLinkStart}zweistufige Verifizierung per Authenticator-App einzurichten{linkTagEnd}.{lineBreak}{lineBreak}Diese Anmeldeanfrage wurde von \n {geolocation} aus erhalten.{lineBreak}{lineBreak}Danke{lineBreak}{lineBreak}Das Roblox-Team","Description.LoginOneTimePasscodeEmail.V2.Body":"Hallo,{lineBreak}{lineBreak}der Code für die einmalige Roblox-Anmeldung ist{boldStart}{code}{boldEnd}. Gib ihn im Anmeldefenster ein, um dich anzumelden. Dieser Code läuft in 15 Minuten ab. Bitte beachte, dass dieser Code nicht für die zweistufige Verifizierung ist.{lineBreak}{lineBreak}Gib diesen Code {boldStart}nicht{boldEnd} weiter. Wir würden dich {boldStart}niemals{boldEnd} kontaktieren und danach fragen. Falls du diesen Code nicht angefordert hast, kannst du diese E-Mail ignorieren. Jemand anderes könnte deine E-Mail-Adresse versehentlich eingegeben haben.{lineBreak}{lineBreak}Diese Anfrage zur Anmeldung stammt aus {geolocation}.{lineBreak}{lineBreak}Vielen Dank{lineBreak}{lineBreak}Das Roblox-Team","Description.OneTimePasscodeEmail.V1.Subject":"{code} ist dein einmaliger Roblox-Code","Description.OneTimePasscodeEmail.V2.Subject":"{code} ist dein Code für die einmalige Roblox-Anmeldung","Description.OptionalPersonalInformationTerms":"Ich gebe meine Einwilligung zur Erfassung und Verarbeitung von {OptionalPersonalInformationLink}","Description.OverseasPersonalInformationTerms":"Ich gebe meine Einwilligung zur {OverseasPersonalInformationTransferLink}","Description.PasskeyRemovalEmailBody.V2.Body":"Wir haben festgestellt, dass ein Passkey von deinem Roblox-Konto entfernt wurde: {username}. Wenn du ihn nicht entfernen wolltest oder glaubst, dass diese Änderung von jemand anders unbeabsichtigt vorgenommen wurde, klicke bitte auf diesen Link, um die {linkTagWithActionLinkStart}Aktion{linkTagEnd} rückgängig zu machen.{lineBreak}{lineBreak}Wenn du mit der Änderung zufrieden bist, brauchst du nichts weiter tun. Bitte antworte nicht auf diese Nachricht. Solltest du Fragen haben, lies bitte diese {linkTagWithHelpLinkStart}Roblox-Hilfeseite{linkTagEnd}.{lineBreak}{lineBreak}Diese Nachricht wurde von roblox.com generiert.","Description.ReauthOneTimePasscodeEmail.V1.Body":"Hallo,{lineBreak}{lineBreak}{boldStart}{code}{boldEnd} ist dein einmaliger Roblox-Code. Gib ihn auf dem Anmeldebildschirm ein, um dich anzumelden. Dieser Code läuft in 15 Minuten ab.{lineBreak}{lineBreak}Teile diesen Code mit {boldStart}niemandem{boldEnd}. Wir würden dich {boldStart}niemals{boldEnd} kontaktieren, um deinen Code zu erfragen. Wenn du diesen Code nicht angefordert hast, musst du nichts weiter tun. Wenn du mehrere Codes erhältst, die du nicht angefordert hast, empfehlen wir dir dringend, eine andere E-Mail-Adresse mit deinem Konto zu verbinden und {linkTagWithAuthenticatorHelpLinkStart}zweistufige Verifizierung per Authenticator-App einzurichten{linkTagEnd}.{lineBreak}{lineBreak}Diese Anfrage für den einmaligen Code für Roblox wurde von {geolocation} aus erhalten.{lineBreak}{lineBreak}Vielen Dank{lineBreak}{lineBreak}Das Roblox-Team","Description.RequiredPersonalInformationTerms":"Ich gebe meine Einwilligung zur Erfassung und Verarbeitung von {RequiredPersonalInformationLink}","Description.ReviewAndConsentToTerms":"Bitte lies und akzeptiere im Namen deines Kindes die folgenden Bedingungen. Du hast die Wahl, den einzelnen Bedingungen zuzustimmen oder nicht zuzustimmen. Dein Kind darf weiterhin Roblox verwenden, wenn du den optionalen Bedingungen nicht zustimmst.","Description.SendVerificationCode":"Wir senden deinen Eltern einen Verifizierungscode, damit sie dir bei der Kontoerstellung helfen können","Description.SentEmail":"Wir haben eine E-Mail gesendet an","Description.TermsConditionsAndPrivacyPolicy":"Ich habe die Nutzungsbedingungen der Benutzervereinbarung überprüft und akzeptiert und erkenne die Datenschutzrichtlinie an ","Description.ThirdPartyPersonalInformationTerms":"Ich gebe meine Einwilligung zur {ThirdPartyPersonalInformationLink}","Description.U13CSChatbotOneTimePasscodeEmail.V1.Body":"Hallo,{lineBreak}{lineBreak}danke, dass du den Roblox-Kundensupport-Chatbot betreffs des Problems mit dem Konto deines Kindes {username} kontaktiert hast.{lineBreak}Ein Code wird benötigt, um mit der eingereichten Chatbot-Anfrage fortzufahren. Bitte gib den folgenden Code im Roblox-Kundensupport-Chatbot ein: {boldStart}{code}{boldEnd}.{lineBreak}{lineBreak}Verwende diesen Code ausschließlich für den Roblox-Kundensupport-Chatbot.{lineBreak}Wenn du diesen Code nicht angefordert hast, kannst du diese E-Mail einfach ignorieren.{lineBreak}{lineBreak}Vielen Dank{lineBreak}{lineBreak}Das Roblox-Team","Description.U13SignupOneTimePasscodeEmail.V1.Body":"Hallo,{lineBreak}{lineBreak}dein Kind möchte ein Konto auf Roblox erstellen, einer Online-Unterhaltungsplattform, die Kinder dazu befähigt, ihre Fantasie zu nutzen, Dinge zu erstellen und miteinander in immersiven, nutzergenerierten 3D-Welten zu spielen.{lineBreak}{lineBreak}Verifizierungscode: {code}{lineBreak}{lineBreak}Dein Kind hat einen Nutzernamen, sein Geburtsdatum und die E-Mail-Adresse der Eltern angegeben, um ein Konto zu erstellen. Um die Kontoerstellung abzuschließen, musst du zustimmen, dass dein Kind Roblox verwenden darf.{lineBreak}{lineBreak}Gib dazu den unten angegebenen Code im Kontoerstellungsablauf ein und genehmige die Nutzung von Roblox deines Kindes. Durch die Eingabe des Codes stimmst du den {linkTagWithTermsLinkStart}Roblox-Nutzungsbedingungen{linkTagEnd} einschließlich der Schiedsklausel, sowie der {linkTagWithPrivacyPolicyLinkStart}Datenschutzrichtlinie{linkTagEnd} zu, du wirst dein Kind beaufsichtigen und alleinig für die Roblox-Nutzung deines Kindes verantwortlich sein, und du stimmst, wo angebracht, der Verarbeitung der persönlichen Daten deines Kindes in Verbindung mit dem Dienst zu.{lineBreak}{lineBreak}{boldStart}Elternratgeber für Roblox{boldEnd}{lineBreak}{lineBreak}Wir empfehlen dir, unseren Elternratgeber zu lesen, um dich mit unserer Plattform vertraut zu machen und hilfreiche Hinweise über die Gestaltung einer positiven Erfahrung auf Roblox für deine Kinder zu erhalten.{lineBreak}{lineBreak}{boldStart}Datenschutz{boldEnd}{lineBreak}{lineBreak}Du kannst das Konto deines Kindes jederzeit entfernen, indem du unseren Kundensupport unter https://www.roblox.com/support kontaktierst. Deine E-Mail-Adresse wird für keine anderen Zwecke verwendet, nicht an Dritte weitergegeben und nicht mit anderen persönlichen Daten, die von deinem Kind gesammelt wurden, verbunden. Bitte lies unsere Datenschutzrichtlinie für weitere Informationen.{lineBreak}{lineBreak}Vielen Dank{lineBreak}{lineBreak}Das Roblox-Team","Description.U13SignupOneTimePasscodeEmail.V2.Body":"Hallo, {lineBreak}{lineBreak}Dein Kind hat darum gebeten, ein Konto auf Roblox zu erstellen, einer Online-Unterhaltungsplattform, auf der Kinder ihre Fantasie benutzen, Dinge erstellen und gemeinsam in immersiven, nutzererstellten 3D-Welten spielen können.{lineBreak}{lineBreak}{boldStart}Verifizierungscode:{code}{boldEnd}{lineBreak}{lineBreak}Dein Kind hat uns einen Nutzernamen, ein Geburtsdatum und eine E-Mail-Adresse der Eltern zur Verfügung gestellt, um ein Konto zu erstellen. Um diesen Vorgang abzuschließen, musst du der Nutzung von Roblox durch dein Kind zustimmen.{lineBreak}{lineBreak}Du musst den oben angegebenen Code eingeben, um die Kontoerstellung abzuschließen, und der Roblox-Nutzung deines Kindes zustimmen. Durch die Eingabe des Codes stimmst du den {linkTagWithTermsLinkStart}Roblox-Bedingungen{linkTagEnd} einschließlich der Schiedsklausel und der {linkTagWithPrivacyPolicyLinkStart}Datenschutzrichtlinie{linkTagEnd} zu, du wirst dein Kind beaufsichtigen und alleinig für die Roblox-Nutzung deines Kindes verantwortlich sein, und du stimmst, wo angebracht, der Nutzung der persönlichen Daten deines Kindes in Zusammenhang mit dem Dienst zu.{lineBreak}{lineBreak}{boldStart}Elternratgeber für Roblox{boldEnd}{lineBreak}{lineBreak}Wir empfehlen dir, den {linkTagWithParentGuideLinkStart}Elternratgeber{linkTagEnd} zu lesen, um dich mit unserer Plattform vertraut zu machen und hilfreiche Tipps zur Erstellung einer positiven Erfahrung deiner Kinder auf Roblox zu erhalten.{lineBreak}{lineBreak}{boldStart}Datenschutz{boldEnd}{lineBreak}{lineBreak}Du kannst das Konto deines Kindes jederzeit entfernen, indem du den Kundenservice unter https://www.roblox.com/support kontaktierst. Deine E-Mail wird nicht für sonstige Zwecke jeglicher Art verwendet, an Dritte weitergegeben oder mit anderen von deinem Kind erhobenen persönlichen Daten kombiniert. Bitte lies unsere Datenschutzrichtlinie für weitere Informationen.{lineBreak}{lineBreak}Vielen Dank{lineBreak}{lineBreak}Das Roblox-Team","Description.UserAgreementsTerms":"Ich habe die {TermsAndConditionsLink} der Benutzervereinbarung überprüft und akzeptiert und erkenne die {PrivacyPolicyLink} an","Label.BackToLogin":"Zurück zur Anmeldung","Label.ChangeEmail":"E-Mail-Adresse ändern","Label.CodeSent":"Code gesendet","Label.ConsentNeeded":"Einverständnis erforderlich","Label.EnterVerificationCode":"Verifizierungscode eingeben","Label.OneTimeCode":"Einmaliger Code","Label.Optional":"Optional","Label.ParentConsentNeeded":"Einwilligung der Eltern erforderlich","Label.ParentEmailAddress":"E-Mail-Adresse deiner Eltern","Label.ParentEmailRequired":"Eltern-E-Mail-Adresse erforderlich","Label.ParentVerificationCode":"Verifizierungscode der Eltern","Label.RefreshPage":"Etwas ist schiefgelaufen. Bitte aktualisiere diese Seite, um dich zu registrieren","Label.Required":"Erforderlich","Label.SixDigitCode":"6-Stelliger Code","Response.ChooseAnotherMethod":"Bitte gehe zurück, um eine andere Methode zu wählen, um dich bei den folgenden Konten anzumelden.","Response.Under13NotAllowed":"Nur Benutzer über 13 können sich mit einem einmaligen Code anmelden."};Roblox.Lang['OneTimePasscodeResources']=Roblox.Lang['Authentication.OneTimePasscode'];

