var Roblox=Roblox||{};Roblox.Lang=Roblox.Lang||{};Roblox.Lang['Feature.AccountSettings']={"Action.Add":"Hinzufügen","Action.AllowAccessContactsV3":"Zugriff auf Kontakte dieses Geräts","Action.Cancel":"Abbrechen","Action.Delete":"Löschen","Action.Done":"Fertig","Action.Join":"Beitreten","Action.Next":"Weiter","Action.Remove":"Entfernen","Action.Report":"Melden","Action.Save":"Speichern","Action.Show":"Anzeigen","Action.Subscribe":"Abonnieren","Description.AccountEmailRevertEmail.From":"{escapeLiteralStart}Roblox-E-Mail zurückgesetzt{escapeLiteralEnd} {fromEmailAddress}","Description.AccountEmailRevertEmail.HtmlBody.V2":"Hallo {username},{lineBreak}{lineBreak}wir haben bemerkt, dass du deine E-Mail-Adresse von {oldEmailAddress} zu {newEmailAddress} geändert hast. Wenn du diese Änderung vorgenommen hast, dann ignoriere diese E-Mail einfach.{lineBreak}{lineBreak}Wenn diese Änderung nicht von dir ausging oder es ein Versehen war, dann klicke auf diesen Link, um die E-Mail-Adresse zurück zu ändern: {aTagWithHref}{revertAccountEmailLinkWithTicket}{hrefEnd}{revertAccountEmailLink}{aTagEnd}. Für die Sicherheit deines Kontos wirst du darum gebeten, ein neues Passwort festzulegen.{lineBreak}{lineBreak} Bitte antworte nicht direkt auf diese Nachricht. Bei Fragen besuche bitte das <a target=\"_blank\" href=\"{accountHelpLink}\">Help Center</a>.","Description.AccountEmailRevertEmail.PlainBody.V2":"Hallo {username},{lineBreak}{lineBreak}wir haben bemerkt, dass du deine E-Mail-Adresse von {oldEmailAddress} zu {newEmailAddress} geändert hast. Wenn du diese Änderung vorgenommen hast, dann ignoriere diese E-Mail einfach.{lineBreak}{lineBreak}Wenn diese Änderung nicht von dir ausging oder es ein Versehen war, dann klicke auf diesen Link, um die E-Mail-Adresse zurück zu ändern: {revertAccountEmailLink}. Für die Sicherheit deines Kontos wirst du darum gebeten, ein neues Passwort festzulegen.{lineBreak}{lineBreak} Bitte antworte nicht direkt auf diese Nachricht. Bei Fragen besuche bitte das Help Center ({accountHelpLink}).","Description.AccountEmailRevertEmail.Subject":"Roblox-E-Mail zurückgesetzt","Description.AllowAccessContactsV2":"Du kannst den Zugang zu deinen Kontakten über die Datenschutzeinstellungen deines Kontos auf deinen Mobilgeräten verwalten","Description.PasskeySkips2sv":"Jedes Mal, wenn du dich mit einem Passkey anmeldest, überspringst du die gewählte zweistufige Verifizierung. Das liegt daran, dass Passkeys sehr sicher sind und dabei helfen zu überprüfen, ob du im Besitz deines physischen Geräts bist.","Description.Subscriptions.NoActive":"Du hast keine aktiven Abonnements","Description.TranslationDisclaimer":"Übersetzungen werden von Roblox generiert und können Fehler enthalten. {linkStart}Mehr erfahren.{linkEnd}","Description.TwoStepVerification":"Eine zusätzliche Ebene der Kontosicherheit {lineBreaks}Zusätzlich zu deinem Passwort fügst du deinem Konto mit zweistufiger Verifizierung eine zusätzliche Sicherheitsebene bei der Anmeldung, Kontowiederherstellung und Transaktionen mit hohen Beträgen hinzu. Hinweis: Du kannst nur eine der unten angezeigten Option gleichzeitig aktivieren.","Description.UsernameChangeEmail.From":"{escapeLiteralStart}Änderung des Roblox-Benutzernamens{escapeLiteralEnd} {fromEmailAddress}","Description.UsernameChangeEmail.Message":"Deine Anfrage zur Benutzernamensänderung wurde bearbeitet. Dein Benutzername wurde von {oldUsername} zu {newUsername} geändert. Solltest du diese Änderung nicht selbst beantragt haben, lies die Hilfetexte zu Kontoinformationen in unserem {startLink}Help Center{endLink}. Bitte antworte nicht direkt auf diese E-Mail, da Antworten auf diese E-Mail nicht erhalten werden.","Description.UsernameChangeEmail.Subject":"Änderung des Roblox-Benutzernamens","Description.VerificationEmail.Body.Over13.V2":"{paragraphStart}Hallo,{paragraphEnd}{paragraphStart}danke, dass du dein Roblox-Konto {emphasisStart}{username}{emphasisEnd} absicherst, indem du deine E-Mail-Adresse angibst.{paragraphEnd}{paragraphStart}Wenn du diese Anfrage gestellt hast, dann klicke bitte auf die Schaltfläche unten, um die Verifizierung abzuschließen:{paragraphEnd}","Description.VerificationEmail.Body.Under13.V2":"{paragraphStart}Hallo,{paragraphEnd}{paragraphStart}dein Kind hat dieses Konto auf Roblox erstellt: {emphasisStart}{username}{emphasisEnd}. Roblox ist eine Online-Unterhaltungsplattform, auf der Kinder in immersiven, benutzererstellten 3D-Welten miteinander spielen, Dinge erschaffen und ihrer Vorstellungskraft freien Lauf lassen können.{paragraphEnd}{paragraphStart}Dein Kind hat uns einen Benutzernamen, sein Geburtsdatum und die E-Mail-Adresse der Eltern mitgeteilt. Bitte bestätige, dass diese E-Mail-Adresse stimmt, indem du auf {emphasisStart} die Schaltfläche unten klickst, um die Verifizierung abzuschließen{emphasisEnd}. Unabhängig davon, ob du die E-Mail-Adresse bestätigst, kann das Kind sein Konto behalten und mit anderen chatten. {paragraphEnd}{paragraphStart}Indem du auf „Ich stimme zu, E-Mail bestätigen“ klickst, akzeptierst du auch, dass (a) du und dein Kind den Roblox- {aTagStartWithHref}{termsOfServiceLink}{hrefEnd}Bedingungen{aTagEnd}, einschließlich der Schiedsklausel zustimmt und (b) du dein Kind beaufsichtigst und alleinig für die Roblox-Nutzung deines Kindes verantwortlich bist.{paragraphEnd}","Description.VerificationEmail.Body.Under13.V4":"{paragraphStart}Hallo,{paragraphEnd}{paragraphStart}du erhältst diese E-Mail, um dich darüber zu informieren, dass dein Kind ein Konto auf Roblox hat mit dem Benutzernamen {emphasisStart}{username}{emphasisEnd}. Du hast die Option, deine E-Mail-Adresse zu bestätigen, um zusätzliche Sicherheits- und Elternkontrollen für das Konto deines Kindes anzuwenden.{paragraphEnd}{paragraphStart}Wir haben folgende Daten erhoben, als dein Kind das Konto auf Roblox erstellt hat: Nutzername, Password, Geburtsdatum und Geschlecht. Vor Kurzem wurde auf dem Konto die E-Mail-Adresse der Eltern durch dich oder dein Kind angegeben. Bitte bestätige, dass diese E-Mail-Adresse stimmt, indem du {emphasisStart}auf die Schaltfläche unten klickst:{emphasisEnd}{paragraphEnd}","Description.VerificationEmail.BodyLower.Over13.V2":"{paragraphStart}Danke{lineBreak}{emphasisStart}Das Roblox-Team{emphasisEnd}{paragraphEnd}","Description.VerificationEmail.BodyLower.Under13.V2":"{paragraphStart}Du kannst die Sicherheits- und Jugendschutzeinstellungen für das Roblox-Konto deines Kindes unter {aTagStartWithHref}{accountSettingsLink}{hrefEnd}{accountSettingsLink}{aTagEnd} anpassen.{paragraphEnd}{paragraphStart}{emphasisStart}Roblox-Hinweise für Eltern{emphasisEnd}{paragraphEnd}{paragraphStart}Wir schlagen vor, dass du unsere Infoseite für Eltern besuchst, um dich mit unserer Plattform vertraut zu machen und für hilfreiche Tipps für eine positive Roblox-Erfahrung für dein Kind: {aTagStartWithHref}{parentalPageLink}{hrefEnd}{parentalPageLink}{aTagEnd}{paragraphEnd}{paragraphStart}{emphasisStart}Datenschutz{emphasisEnd}{paragraphEnd}{paragraphStart} Du kannst das Konto deines Kindes jederzeit entfernen, indem du unseren Kundendienst kontaktierst: {aTagStartWithHref}{supportPageLink}{hrefEnd}{supportPageLink}{aTagEnd}. Deine E-Mail-Adresse wird für keine anderen Zwecke benutzt, nicht an Dritte weitergegeben und nicht mit anderen persönlichen Daten, die von dir oder deinem Kind gesammelt wurden, verbunden. Bitte lies unsere Datenschutzbestimmungen für weitere Informationen:\n {aTagStartWithHref}{privacyPageLink}{hrefEnd}{privacyPageLink}{aTagEnd}.{paragraphEnd}{paragraphStart}Vielen Dank{lineBreak}{emphasisStart}Das Roblox-Team{emphasisEnd}{paragraphEnd}","Description.VerificationEmail.BodyLower.Under13.V4":"{paragraphStart}Nach Bestätigung deiner E-Mail-Adresse hast du die Möglichkeit, das Passwort deines Kindes (falls nötig) zurückzusetzen, Informationen über die Kontoaktivitäten deines Kindes zu erhalten und die Sicherheits- und Kindersicherungseinstellungen für ihr Roblox-Konto anzupassen unter https://www.roblox.com/my/account#!.{paragraphEnd}{paragraphStart}Wenn du deine E-Mail-Adresse nicht bestätigen möchtest, kann dein Kind sein Konto trotzdem weiter benutzen, auf Roblox spielen und auf die meisten Funktionen zugreifen, einschließlich gefiltertem Textchat.{paragraphEnd}{paragraphStart}Deine E-Mail-Adresse wird für keine anderen Zwecke genutzt, nicht an Dritte weitergegeben und nicht mit anderen persönlichen Daten, die von deinem Kind erhoben wurden, kombiniert. Abgesehen von der E-Mail-Adresse der Eltern erfassen, verwenden oder legen wir keine persönlichen Informationen von minderjährigen Benutzern offen.{paragraphEnd}{paragraphStart}Bitte lies unsere Datenschutzrichtlinie für weitere Informationen unter https://www.roblox.com/info/privacy.{paragraphEnd}{paragraphStart}{emphasisStart}Roblox Elternratgeber{emphasisEnd}{paragraphEnd}{paragraphStart}Roblox ist eine Online-Unterhaltungsplattform, die es Kindern ermöglicht, in immersiven, nutzergenerierten 3D-Welten ihre Fantasie zu nutzen, zu erstellen und miteinander zu spielen.{paragraphEnd}{paragraphStart}Wir empfehlen dir, unseren Elternratgeber zu besuchen, um dich mit unserer Plattform vertraut zu machen und hilfreiche Tipps zum Erstellen einer positiven Erfahrung für dein Kind auf Roblox zu erhalten: https://www.roblox.com/info/parents{paragraphEnd}{paragraphStart}{emphasisStart}Weitere wichtige Informationen{emphasisEnd}{paragraphEnd}{paragraphStart}Du kannst jederzeit deinem Kind die Nutzung von Roblox untersagen, fordern, dass wir das Roblox-Konto deines Kindes löschen und/oder fordern, dass wir deine E-Mail-Adresse löschen. Um dies zu tun, kontaktiere bitte den Kundendienst unter https://www.roblox.com/support.{paragraphEnd}{paragraphStart}Wenn du deinem Kind erlaubst, ein Roblox-Konto zu nutzen, stimmst du zu, dass (a) du und dein Kind den {aTagStartWithHref}{termsOfServiceLink}{hrefEnd}Roblox-Nutzungsbedingungen{aTagEnd} einschließlich der Schiedsklausel zustimmen und (b) du dein Kind beaufsichtigen und alleinig für dessen Nutzung von Roblox verantwortlich sein wirst.{paragraphEnd}{paragraphStart}Vielen Dank{paragraphEnd}{paragraphStart}Das Roblox-Team{paragraphEnd}","Description.VerificationEmail.ButtonText.Over13.V2":"E-Mail-Adresse verifizieren","Description.VerificationEmail.ButtonText.Under13.V2":"I stimme zu, E-Mail bestätigen","Description.VerificationEmail.Footer.Over13.V2":"Antworte nicht direkt auf diese E-Mail. Du hast diese E-Mail erhalten, weil es einen Versuch gab, dein Roblox-Konto mit deiner E-Mail-Adresse zu verifizieren. Wenn du das nicht warst, dann ignoriere diese E-Mail bitte.","Description.VerificationEmail.Footer.Under13.V2":"Antworte nicht direkt auf diese E-Mail. Du hast diese E-Mail erhalten, weil jemand versucht hat, dein Roblox-Konto mit deiner E-Mail-Adresse zu verifizieren. Wenn du das nicht warst, dann ignoriere diese E-Mail bitte.","Description.VerificationEmail.From.Over13":"{escapeLiteratStart}Roblox-E-Mail-Verifizierung{escapeLiteralEnd} {fromEmailAddress}","Description.VerificationEmail.From.Under13":"{escapeLiteratStart}Roblox-Kontoautorisierung{escapeLiteralEnd} {fromEmailAddress}","Description.VerificationEmail.Header.Over13.V2":"Roblox-E-Mail-Verifizierung","Description.VerificationEmail.Header.Under13.V2":"Roblox-E-Mail-Verifizierung","Description.VerificationEmail.HtmlBody.Over13":"Hallo Roblox-Nutzer,{lineBreak}{lineBreak}wir freuen uns, dass du dein Konto ({username}) durch eine E-Mail-Adresse schützen möchtest.{lineBreak}Wenn du die E-Mail-Adresse, die mit deinem Roblox-Konto verknüpft ist, verifizierst, machst du dein Konto sicherer.{lineBreak}Bitte klicke auf die Schaltfläche unten, um die Verifizierung abzuschließen.{lineBreak}{lineBreak}{aTagStartWithHref}{verificationLink}{targetBlank}{buttonStart}E-Mail-Adresse verifizieren{buttonEnd}{aTagEnd}","Description.VerificationEmail.HtmlBody.Under13":"Hallo,{lineBreak}{lineBreak}dein Kind hat das Konto {boldTagStart}{username}{boldTagEnd} auf Roblox erstellt. Roblox ist eine Online-Unterhaltungsplattform, auf der Kinder ihrer Fantasie freien Lauf lassen und gemeinsam in immersiven, von unseren Benutzern erschaffenen 3D-Welten spielen und Inhalte erstellen können. Unsere Plattform bietet auch ein kostenloses Entwickler-Tool namens \"Roblox Studio, mit dem Benutzer alles in ihrer Vorstellungskraft entwickeln können: von simplen Drag-and-Drop-Konstruktionen bis hin zu komplexen Multiplayer-Spielen. Millionen von Kindern nutzen Roblox, um selbst zu erleben, wie es sich anfühlt, den ultimativen Vergnügungspark zu bauen, als professioneller Rennfahrer anzutreten, bei einer Modenschau zu glänzen oder einfach nur ein Traumhaus zu bauen und sich dort mit Freunden zu treffen.{lineBreak}{lineBreak}Durch diese E-Mail möchten wir dir mitteilen, dass dein Kind seinen Benutzernamen, Geburtstag und die E-Mail-Adresse seiner Eltern angegeben hat. Die E-Mail-Adresse der Eltern wird nur verwendet, um das Konto zu verwalten, vergessene Passwörter zurückzusetzen und die Eltern darüber zu benachrichtigen, wenn sich der Kontozugriff des Kinds ändert. Um deine E-Mail-Adresse zu verifizieren, klicke bitte auf die Schaltfläche unten:{lineBreak}{lineBreak}{aTagStartWithHref}{verificationLink}{hrefEnd}{buttonStart}E-Mail-Adresse verifizieren{buttonEnd}{aTagEnd}{lineBreak}{lineBreak}{boldTagStart}Über Roblox{boldTagEnd}{lineBreak}{lineBreak}Roblox setzt sich dafür ein, eine unterhaltsame, familienfreundliche Umgebung bereitzustellen. Wir verbessern unsere Sicherheitsmaßnahmen fortwährend und arbeiten mit Experten für digitale Sicherheit zusammen, um dafür zu sorgen, dass allen Spielern ein sicherer, angenehmer Ort zum Spielen und Chatten sowie für gemeinsame, kreative Projekte zur Verfügung steht. Wir empfehlen dir, unseren Elternratgeber zu lesen, um dich mit unserer Plattform vertraut zu machen. Dort findest du auch hilfreiche Tipps, mit denen du ein positives Erlebnis für deine Kinder auf Roblox gewährleisten kannst: {aTagStartWithHref}{parentalPageLink}{hrefEnd}{parentalPageLink}{aTagEnd}{lineBreak}{lineBreak}Roblox bietet auch {boldTagStart}Kindersicherungseinstellungen{boldTagEnd}. Eltern können eine Eltern-PIN aktivieren und die Kommunikations- und Chateinstellungen für ihre Kinder anpassen. Diese Einstellungen findest du in den Reitern für Sicherheit und Datenschutz in den Kontoeinstellungen, während du beim Konto deines Kindes angemeldet bist.{lineBreak}{lineBreak}Um eine Eltern-PIN hinzuzufügen, besuche bitte: {aTagStartWithHref}{accountSecurityLink}{hrefEnd}{accountSecurityLink}{aTagEnd}.{lineBreak}{lineBreak}Um die Chateinstellungen anzupassen, besuche bitte: {aTagStartWithHref}{accountPrivacyLink}{hrefEnd}{accountPrivacyLink}{aTagEnd}.{lineBreak}{lineBreak}{boldTagStart}Datenschutz{boldTagEnd}{lineBreak}{lineBreak}Du kannst das Konto deines Kindes entfernen, indem du den Kundenservice hier kontaktierst: {aTagStartWithHref}{supportPageLink}{hrefEnd}{supportPageLink}{aTagEnd}. Deine E-Mail-Adresse wird zu keinen anderen Zwecken verwendet und nicht an Dritte weitergegeben oder mit anderen persönlichen Daten, die wir von deinem Kind erhalten haben, verknüpft. Weitere Informationen kannst du unseren Datenschutzrichtlinien hier entnehmen: {aTagStartWithHref}{privacyPageLink}{hrefEnd}{privacyPageLink}{aTagEnd}.{lineBreak}{lineBreak}{lineBreak}Vielen Dank{lineBreak}{lineBreak}Das Roblox-Team {lineBreak}{lineBreak} Bitte antworte nicht direkt auf diese E-Mail. {lineBreak}{lineBreak} {aTagStartWithHref}{robloxWebsiteLink}{hrefEnd}{robloxWebsiteLink}{aTagEnd} {lineBreak}{lineBreak} {aTagStartWithHref}{supportPageLink}{hrefEnd}{supportPageLink}{aTagEnd}","Description.VerificationEmail.Links.Over13.V2":"{aTagStartWithHref}{AccountSafetyArticleLink}{hrefEnd}Kontosicherheit{aTagEnd} | {aTagStartWithHref}{supportPageLink}{hrefEnd}Support{aTagEnd}","Description.VerificationEmail.Links.Under13.V2":"{aTagStartWithHref}{parentalPageLink}{hrefEnd}Für Eltern{aTagEnd} | {aTagStartWithHref}{supportPageLink}{hrefEnd}Support{aTagEnd}","Description.VerificationEmail.PlainBody.Over13":"Hallo Roblox-Nutzer,{lineBreak}{lineBreak}wir freuen uns, dass du dein Konto ({username}) durch eine E-Mail-Adresse schützen möchtest.{lineBreak}Wenn du die E-Mail-Adresse, die mit deinem Roblox-Konto verknüpft ist, verifizierst, machst du dein Konto sicherer.{lineBreak}Bitte klicke auf den folgenden Link, um die Verifizierung abzuschließen:{lineBreak}{verificationLink}.\n","Description.VerificationEmail.Subject.Over13":"Roblox-E-Mail-Verifizierung","Description.VerificationEmail.Subject.Over13.V2":"Roblox-E-Mail-Verifizierung: {username}","Description.VerificationEmail.Subject.Under13":"Roblox-Kontoautorisierung","Description.VerificationEmail.Subject.Under13.V2":"Roblox-E-Mail-Bestätigung: {username}","Description.VerificationEmail.Subject.Under13.V4":"Roblox-Bestätigung der Eltern-E-Mail: {username}","Heading.Billing":"Zahlungen","Heading.Dialog.DisableUpdateFriendsAboutMyActivity":"Aktualisierungen über Freundesaktivitäten deaktiviert","Heading.Dialog.ShareCurrentExperiencesWithFriends":"Du teilst jetzt deine aktuelle Experience mit Freunden","Heading.LoginMethods":"Anmeldemethoden","Heading.PageTitle":"Einstellungen","Heading.PasskeyCreated":"Passkey erstellt","Heading.PrivateServers":"Private Server","Heading.Subscriptions.Active":"Aktiv ({activeNumber})","Label.CameraNotAvailable":"Kamera ist auf bestimmten Geräten nicht verfügbar.","Label.CameraNotSupported":"Kamera ist auf bestimmten Geräten nicht verfügbar. {linkStart}Mehr erfahren{linkEnd}","Label.Cancel":"Abbrechen","Label.CreatedBy":"Von {creator}","Label.DropDown.No":"Nein","Label.DropDown.Yes":"Ja","Label.Email":"E-Mail-Adresse:","Label.Enable":"Aktivieren","Label.Manage":"Verwalten","Label.Passkey":"Passkey:","Label.Password":"Passwort:","Label.Phone":"Handynummer:","Label.Repeat":"Wiederholung","Label.ToolTip.UpdateFriendsAboutMyActivity":"Wenn du \"Ja\" wählst, können deine Freunde Updates über einige deiner letzten Aktivitäten in Experiences erhalten.","Label.UpdateFriendsAboutMyActivity":"Freunde über meine Aktivität auf dem Laufenden halten?","Label.Username":"Benutzername:","MessageInvalidEmail":"Ungültige E-Mail-Adresse","MessagePinLockedError":"PIN ist gesperrt.","MessageSettingsUpdateSuccess":"Deine Einstellungen wurden aktualisiert.","MessageUnknownError":"Ein unbekannter Fehler ist aufgetreten.","Response.Dialog.DisableUpdateFriendsAboutMyActivity":"Da du dein aktuelle Experience nicht mehr mit Freund teilst, können deine Freunde auch keine Aktualisierungen über deine Aktivität erhalten.","Response.Dialog.ShareCurrentExperiencesWithFriends":"Da du Updates über Freundesaktivitäten aktiviert hast, können deine Freunde jetzt sehen, in welcher Experience du dich gerade befindest, und mitmachen.","Response.VerificationError":"Systemfehler während der Verifizierung aufgetreten."};Roblox.Lang['AccountSettingsResources']=Roblox.Lang['Feature.AccountSettings'];

