var Roblox=Roblox||{};Roblox.Lang=Roblox.Lang||{};Roblox.Lang['Feature.Tracking']={"Action.RequestData":"Deine Daten anfordern","Action.SavePreferences":"Einstellungen speichern","Action.SetCookieOptions":"Cookie-Optionen einstellen","Description._cfduid":"Zendesk Kundenservice","Description.CookieBannerContent":"Wir verwenden Cookies, um deine Erfahrung auf unserer Website zu personalisieren und zu verbessern. Besuche unsere {privacyPolicyLink} für weitere Informationen über unsere Datensammelpraktiken. Wenn du auf „Zustimmen“ klickst, akzeptierst du unsere Verwendung von Cookies, die für diese Zwecke in den Einstellungen aufgeführt sind. Um Einsicht auf die komplette Liste der Unternehmen zu gelangen, die diese Cookies und weitere Technologien verwenden, und um uns mitzuteilen, ob sie diese auf deinem Gerät verwenden dürfen oder nicht, greife auf das Cookie Consent Tool zu. Diese Mitteilung wird dir nur einmal angezeigt, aber du kannst deine Einstellungen jederzeit im Cookie Consent Tool ändern.","Description.CookiePreferenceLink":"Cookie-Einstellungen verwalten","Description.CookieT":"Nutzer-Authentifizierungs-Token-Cookie","Description.DataCollected":"Vertraulich: Finanzielle Informationen","Description.DataRetention":"Solange wie nötig, um geschäftliche Notwendigkeit zu erfüllen, oder wie gesetzlich vorgeschrieben.","Description.DataSharing":"Aggregierte Daten werden mit Dritten geteilt, Anonyme Daten werden mit Dritten geteilt, Personenbezogene Daten werden mit Dritten geteilt, Vertrauliche Daten werden mit Dritten geteilt.","Description.DataUse":"Adserver, Targeted Advertising, Analyse/Messungen, Anpassung von Inhalten, Cross-Device Tracking, Optimierung","Description.GAReadMore":"Mehr über {googleAnalyticsLink} lesen","Description.GoogleAnalyticsPurpose":"Google Analytics gewährt Unternehmen Einblick in ihren Website-Verkehr und ihre Marketing-Wirksamkeit. Google Analytics hilft bei der Festlegung der richtigen Schlagwörter, der Bestimmung der besten Zielmärkte sowie der Kundenbindung und -gewinnung. ","Description.GuestData":"Gastmodus ist nicht mehr verwendbar","Description.HasGmid":"Authentifizierung","Description.HelpCenterSession":"Zu finden auf en.help.roblox.com","Description.IclVisitorLangJs":"Spracheinstellung auf corp.roblox.com","Description.InformationCollection":"Wir möchten transparent darüber sein, welche Daten wir und unsere Partner sammeln und wie wir diese verwenden, damit du die beste Kontrolle über deine persönlichen Daten ausüben kannst. Für weitere Informationen, sieh bitte unsere Datenschutzrichtlinien durch.","Description.InformationCollection2":"Wir verwenden diese Information, um die Leistung und die Benutzererfahrung unserer Website-Besucher zu verbessern. Darin eingeschlossen sind Verbesserungen der Suchergebnisse, das Anzeigen von relevanteren Inhalten und Promo-Materialien, bessere Kommunikation sowie verbesserte Website-Leistung.","Description.InformationPartnerCollection":"Wir benutzen die folgenden Drittanbieter, um deine Erfahrung auf Roblox zu verbessern. Sie benutzen eventuell Cookies und andere Mechanismen zum Einholen von Nutzungsstatistiken auf unserer Website. Du kannst dieses Sammeln von Daten deaktivieren, indem du den Analyse-Schalter auf \"aus\" stellst.","Description.PrivacyPolicy":"Datenschutzrichtlinien","Description.RBXEventTrackerV2":"A/B Testing","Description.RBXIDCHECK":"Cookie, das die Verifizierung in 2 Schritten auf diesem Browser umgehen lässt","Description.RBXImageCache":"Authentifizierung","Description.RbxIp2":"Sicherheit: Floodcheck-Cookie","Description.RBXSource":"Analyse: Für Akquise von Benutzer und Anzeige-/Source-Attribution","Description.RBXViralAcquisition":"Analyse: Für Akquise von Benutzern über Social-Media-Links","Description.ROBLOSECURITY":"Cookie, mit dem ein Benutzer angemeldet bleibt","Description.Undisclosed":"Unbekannt","Description.WpmlBrowserRedirectTest":"Browser-Umleitungstest","Heading.AnalyticsCookies":"Analyse-Cookies","Heading.CompanyCollection":"Welche Daten sammelt dieses Unternehmen?","Heading.CookieSettings":"Cookie-Optionen","Heading.EssentialCookies":"Erforderliche Cookies","Heading.GoogleAnalytics":"Google Analytics","Heading.GoogleAnalyticsPurpose":"Wozu dient Google Analytics?","Heading.InformationCollection":"Daten, die wir über dich sammeln","Heading.InformationCollection2":"Daten, die wir sammeln","Heading.InformationPartnerCollection":"Daten, die unsere Partner sammeln","Label.DataCollected":"Gesammelte Daten","Label.DataRetention":"Datenhaltung\n","Label.DataSharing":"Teilen von Daten","Label.DataStorage":"Datenspeicherung","Label.DataUse":"Verwendung von Daten","Label.OwnedBy":"Gehört","Label.Website":"Website"};Roblox.Lang['TrackingResources']=Roblox.Lang['Feature.Tracking'];

